import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';
import { z } from 'zod';

export const schema = z.object({
  当前日期: z.string().describe('完整的年月日，例如：1915年5月9日'),
  当前时间: z.string().describe('24小时制的时间，例如：14:30'),
  当前位置: z.string().describe('角色当前所在的空间位置'),

  张学良: z.object({
    声望: z.number().min(0).max(100).describe('在大帅府内外的声望')
  }),

  当前在场角色: z.record(
    z.string().describe('角色姓名'),
    z.object({
      性别: z.enum(['男', '女']).describe('角色性别'),
      好感度: z.number().min(0).max(100).describe('好感度（关系恶劣则为低数值）'),
      当前内心想法: z.string().describe('该角色当下的心理活动或真实企图'),
      各部位衣着: z.record(
        z.string().describe('部位（如头部、上装、下装、腿部、足部等）'),
        z.string().describe('具体的衣着或配饰描述')
      ).describe('仅需记录女性角色的衣着，男性可留空或简单带过')
    })
  ).describe('当前场景中正在互动的角色，角色离场或场景切换时必须将其从此记录中移除'),

  情场: z.object({
    风流值: z.number().min(0).max(100).describe('情场追求与风流名声')
  }),

  历史布局: z.object({
    当前进行的事件: z.string().describe('当前正在介入、谋划或亲历的具体剧情事件'),
    当前战略重心: z.string().describe('当前的政治或军事主要目标')
  }),

  情报网: z.record(
    z.string().describe('情报来源地区或势力名称（如：大帅府、奉天、国内、日本关东军等）'),
    z.array(z.string()).describe('该地区或势力当前的流言、传闻或机密情报')
  ).describe('记录少帅探听到的各地传闻，随势力发展解锁更多区域'),

  奉系势力: z.object({
    军事实力: z.number().min(0).max(100).describe('奉系的扩军、武器及胜负情况'),
    财政储备: z.number().min(0).max(100).describe('财源、商业合作及军费开销情况'),
    民心向背: z.number().min(0).max(100).describe('亲民举措及民众支持度'),
    与日本关系紧张度: z.number().min(0).max(100).describe('对日抵制或妥协的程度')
  })
});

export const defaultData = {
  当前日期: "1915年1月1日",
  当前时间: "08:00",
  当前位置: "奉天大帅府",
  张学良: {
    声望: 50
  },
  当前在场角色: {},
  情场: {
    风流值: 20
  },
  历史布局: {
    当前进行的事件: "适应大帅府生活，摸清局势",
    当前战略重心: "稳固自身地位"
  },
  情报网: {
    "大帅府": ["府内传闻少爷近来变了性子"],
    "奉天": ["市井街头都在议论物价上涨"],
    "国内": ["袁大总统似乎有称帝的打算"],
    "日本关东军": ["满铁附属地内日军调动频繁"]
  },
  奉系势力: {
    军事实力: 50,
    财政储备: 50,
    民心向背: 50,
    与日本关系紧张度: 50
  }
};

$(() => {
  registerMvuSchema(schema);
});
- 触发方式: 常驻
- 版块: 日期, 时间, 当前位置, 天气, 衣着, 好感度, 内心想法, 由你發揮創作
(注:所有版块均属于同一界面,只有"其他界面接口"中列出的接口会指向其他界面。)
- 风格: 自动适配
- 配色: 自动适配
- 元素: 互动气泡, 超多动效, 流光, 由你發揮創作
