<style>
/* HUD 主题变量 */
:root {
    --hud-main: #00ff41;
    --hud-dark: #001a08;
    --hud-bg: rgba(2, 12, 4, 0.85);
    --hud-glass: rgba(0, 255, 65, 0.05);
    --hud-border: #004d14;
    --hud-text: #e0ffe8;
    --hud-danger: #ff003c;
    --hud-warn: #ffaa00;
}

/* 容器与折叠 */
.system-hud-container {
    width: 100%;
    margin: 10px 0;
    font-family: "Courier New", Courier, monospace;
    background: var(--hud-bg);
    border: 1px solid var(--hud-border);
    border-radius: 8px;
    box-shadow: 0 0 15px rgba(0, 255, 65, 0.15), inset 0 0 20px rgba(0, 255, 65, 0.05);
    backdrop-filter: blur(10px);
    overflow: hidden;
    position: relative;
    transition: all 0.3s ease;
}

/* 扫描线动画 */
.system-hud-container::before {
    content: " ";
    display: block;
    position: absolute;
    top: 0;
    left: 0;
    bottom: 0;
    right: 0;
    background: linear-gradient(rgba(18, 16, 16, 0) 50%, rgba(0, 0, 0, 0.25) 50%), linear-gradient(90deg, rgba(255, 0, 0, 0.06), rgba(0, 255, 0, 0.02), rgba(0, 0, 255, 0.06));
    z-index: 2;
    background-size: 100% 2px, 3px 100%;
    pointer-events: none;
}

.hud-summary {
    padding: 12px 15px;
    display: flex;
    justify-content: space-between;
    align-items: center;
    cursor: pointer;
    color: var(--hud-main);
    font-size: 14px;
    font-weight: bold;
    text-transform: uppercase;
    letter-spacing: 1px;
    list-style: none;
    border-bottom: 1px solid transparent;
    transition: all 0.3s;
}

.hud-summary::-webkit-details-marker { display: none; }
.system-hud-container[open] .hud-summary { border-bottom: 1px solid var(--hud-border); background: rgba(0, 255, 65, 0.1); }

.hud-blink { animation: blinker 2s linear infinite; }
@keyframes blinker { 50% { opacity: 0.3; } }

.hud-content-wrapper {
    padding: 15px;
    color: var(--hud-text);
    font-size: 13px;
    position: relative;
    z-index: 3;
}

/* 快捷指令区 */
.hud-cmd-deck {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 10px;
    margin-bottom: 20px;
}

.hud-btn {
    background: var(--hud-dark);
    border: 1px solid var(--hud-border);
    color: var(--hud-main);
    padding: 10px 5px;
    text-align: center;
    border-radius: 4px;
    cursor: pointer;
    font-weight: bold;
    transition: all 0.2s;
    position: relative;
    overflow: hidden;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 5px;
}
.hud-btn i { font-size: 18px; }

.hud-btn::after {
    content: ''; position: absolute; top: -50%; left: -50%; width: 200%; height: 200%;
    background: rgba(255, 255, 255, 0.1); transform: rotate(45deg); transition: all 0.3s;
    opacity: 0;
}
.hud-btn:hover { background: var(--hud-main); color: #000; box-shadow: 0 0 10px var(--hud-main); }
.hud-btn:hover::after { opacity: 1; left: 100%; top: 100%; }

/* 面板双栏布局 */
.hud-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 15px;
}
@media (max-width: 600px) { .hud-grid { grid-template-columns: 1fr; } }

.hud-panel {
    background: var(--hud-glass);
    border: 1px solid var(--hud-border);
    border-radius: 4px;
    padding: 10px;
    position: relative;
}

.hud-panel-title {
    color: var(--hud-main);
    font-size: 12px;
    position: absolute;
    top: -8px;
    left: 10px;
    background: rgb(2, 12, 4);
    padding: 0 5px;
    letter-spacing: 1px;
}

/* 进度条设计 */
.hud-bar-row { display: flex; align-items: center; margin-top: 8px; justify-content: space-between; }
.hud-bar-label { width: 50px; font-size: 12px; color: #aaa; }
.hud-bar-bg { flex-grow: 1; height: 6px; background: rgba(255,255,255,0.1); margin: 0 10px; position: relative; border-radius: 3px; overflow: hidden; }
.hud-bar-fill { height: 100%; position: absolute; left: 0; top: 0; background: var(--hud-main); box-shadow: 0 0 5px var(--hud-main); transition: width 1s ease-in-out; }
.hud-bar-fill.warning { background: var(--hud-warn); box-shadow: 0 0 5px var(--hud-warn); }
.hud-bar-val { width: 30px; text-align: right; font-weight: bold; color: var(--hud-main); }

/* 在场角色卡片组 */
.hud-chars-container { margin-top: 15px; }
.char-card {
    border-left: 3px solid var(--hud-main);
    background: rgba(0, 255, 65, 0.03);
    padding: 8px 10px;
    margin-bottom: 8px;
    border-radius: 0 4px 4px 0;
    transition: transform 0.2s;
}
.char-card:hover { transform: translateX(5px); background: rgba(0, 255, 65, 0.08); }
.char-header { display: flex; justify-content: space-between; margin-bottom: 5px; }
.char-name { font-weight: bold; color: #fff; }
.char-gender-icon { margin-left: 5px; opacity: 0.7; }
.char-thought { font-style: italic; color: #ccc; font-size: 12px; margin-bottom: 5px; }
.char-thought::before { content: "『"; color: var(--hud-main); }
.char-thought::after { content: "』"; color: var(--hud-main); }
.char-cloth { font-size: 11px; display: inline-block; background: rgba(255,255,255,0.1); padding: 2px 6px; border-radius: 10px; margin-right: 5px; margin-top: 4px; color: #bbb;}

/* 情报网滚动条 */
.intel-ticker {
    margin-top: 15px; background: #000; border: 1px dashed var(--hud-border);
    color: var(--hud-main); padding: 8px; font-size: 12px; height: 75px;
    overflow-y: auto;
}
.intel-item { margin-bottom: 4px; border-bottom: 1px dotted rgba(0,255,65,0.2); padding-bottom: 4px; }
.intel-source { color: var(--hud-warn); font-weight: bold; margin-right: 5px; }
.intel-source::before { content: "["; } .intel-source::after { content: "]"; }

/* 其他杂项 */
.text-highlight { color: var(--hud-main); font-weight: bold; }
</style>

