    const hasTriggerSlash = typeof triggerSlash === 'function';

    // 全局快捷指令执行函数挂载到 window，方便 onclick 调用
    window.executeSysCmd = function(cmdType) {
        if (!hasTriggerSlash) {
            alert("执行模块离线：未找到酒馆全局函数 triggerSlash()");
            return;
        }
        let userInput = "";
        let commandStr = "";

        switch(cmdType) {
            case '听令':
                userInput = prompt("【听令】系统激活。\n请输入目标及强制指令 (格式: 目标姓名 指令动作)：", "");
                if (userInput) commandStr = `/send 听令 ${userInput.trim()} | /trigger`;
                break;
            case '观看':
                userInput = prompt("【观看】视角系统激活。\n请输入监视坐标或人物 (例如: 奉天茶楼 或 张作霖)：", "");
                if (userInput) commandStr = `/send 观看 ${userInput.trim()} | /trigger`;
                break;
            case '绿令':
                userInput = prompt("【绿令】全频扫描系统激活。\n请输入需解析的女性目标姓名：", "");
                if (userInput) commandStr = `/send 绿令 ${userInput.trim()} | /trigger`;
                break;
            case '达令':
                userInput = prompt("【达令】空间跃迁激活。\n请输入目标及目的地 (格式: 目标 目的地，自我传送也可省略目标)：", "");
                if (userInput) commandStr = `/send 达令 ${userInput.trim()} | /trigger`;
                break;
        }
        if (commandStr) triggerSlash(commandStr);
    };

    function updateHud() {
        if (!hasAllVariables || !hasLodash) return;
        const vars = getAllVariables() || {};
        const getV = (path, def) => _.get(vars, 'stat_data.' + path, def);

        // 基础信息
        document.getElementById('hud-sum-date').textContent = getV('当前日期', '1915年1月1日');
        document.getElementById('hud-sum-loc').textContent = getV('当前位置', '未知');
        document.getElementById('hud-time').textContent = getV('当前时间', '00:00');

        // 少帅属性
        const rep = getV('张学良.声望', 50);
        const rom = getV('情场.风流值', 20);
        document.getElementById('bar-rep').style.width = rep + '%'; document.getElementById('val-rep').textContent = rep;
        document.getElementById('bar-rom').style.width = rom + '%'; document.getElementById('val-rom').textContent = rom;

        // 布局与战略
        document.getElementById('hud-evt').textContent = getV('历史布局.当前进行的事件', '待确认');
        document.getElementById('hud-str').textContent = getV('历史布局.当前战略重心', '待确认');

        // 势力数值
        const mil = getV('奉系势力.军事实力', 50);
        const fin = getV('奉系势力.财政储备', 50);
        const pop = getV('奉系势力.民心向背', 50);
        const ten = getV('奉系势力.与日本关系紧张度', 50);
        document.getElementById('bar-mil').style.width = mil + '%'; document.getElementById('val-mil').textContent = mil;
        document.getElementById('bar-fin').style.width = fin + '%'; document.getElementById('val-fin').textContent = fin;
        document.getElementById('bar-pop').style.width = pop + '%'; document.getElementById('val-pop').textContent = pop;
        document.getElementById('bar-ten').style.width = ten + '%'; document.getElementById('val-ten').textContent = ten;

        // 当前在场角色处理
        const charObj = getV('当前在场角色', {});
        const charContainer = document.getElementById('hud-chars-list');
        if (Object.keys(charObj).length === 0) {
            charContainer.innerHTML = '<div style="text-align: center; color: #555; padding: 10px;">(生体雷达未探测到在场目标)</div>';
        } else {
            let charHtml = '';
            for (const [name, cData] of Object.entries(charObj)) {
                let icon = cData.性别 === '女' ? '<i class="fas fa-venus" style="color:#ff66b2"></i>' : '<i class="fas fa-mars" style="color:#66b2ff"></i>';
                let clothHtml = '';
                if (cData.性别 === '女' && cData.各部位衣着) {
                    for(const [part, desc] of Object.entries(cData.各部位衣着)) {
                        clothHtml += `<span class="char-cloth">${part}: ${desc}</span>`;
