                    <div class="char-thought">${cData.当前内心想法 || '无法解析神经波段'}</div>
                    ${clothHtml ? `<div>${clothHtml}</div>` : ''}
                </div>`;
            }
            charContainer.innerHTML = charHtml;
        }

        // 情报处理
        const intelObj = getV('情报网', {});
        const intelContainer = document.getElementById('hud-intel-list');
        let intelHtml = '';
        for (const [source, list] of Object.entries(intelObj)) {
            if (Array.isArray(list) && list.length > 0) {
                list.forEach(msg => {
                    intelHtml += `<div class="intel-item"><span class="intel-source">${source}</span> ${msg}</div>`;
                });
            }
        }
        intelContainer.innerHTML = intelHtml || '<div style="color:#555; text-align:center;">暂无截获通讯信号...</div>';
        // 自动卷到最新（底部）
        intelContainer.scrollTop = intelContainer.scrollHeight;
    }

    // 初始化并设置1秒延时动画避免突兀
    setTimeout(updateHud, 200);
})();
</script>
