(function() {
    const hasAll = typeof getAllVariables === 'function';
    const hasLo = typeof _ !== 'undefined' && typeof _.get === 'function';
    const hasTr = typeof triggerSlash === 'function';

    // 交互弹窗与指令执行
    window.execCmd = function(type) {
        if (!hasTr) { alert("指令模块离线。"); return; }
        let input="", cmd="";
        switch(type) {
            case '听令': input = prompt("【脑域覆写】\n请输入目标与指令 (格式: 目标 行动)："); if(input) cmd = `/send 听令 ${input} | /trigger`; break;
            case '观看': input = prompt("【全知监控】\n请输入监视坐标或人物："); if(input) cmd = `/send 观看 ${input} | /trigger`; break;
            case '绿令': input = prompt("【深层解析】\n请输入需扫描的女性目标："); if(input) cmd = `/send 绿令 ${input} | /trigger`; break;
            case '达令': input = prompt("【跃迁引击】\n请输入目标与目的地 (自我传送可省略目标)："); if(input) cmd = `/send 达令 ${input} | /trigger`; break;
        }
        if(cmd) triggerSlash(cmd);
    };

    function render() {
        if (!hasAll || !hasLo) return;
        const vars = getAllVariables() || {};
        const v = (p, d) => _.get(vars, 'stat_data.' + p, d);

        // Header
        document.getElementById('v-date').textContent = v('当前日期', '1915-01-01');
        document.getElementById('v-time').textContent = v('当前时间', '00:00');
        document.getElementById('v-loc').textContent = v('当前位置', '坐标丢失');

        // Profile & Faction Bars
        const setBar = (id, path, def) => {
            let val = v(path, def);
            document.getElementById('bar-'+id).style.width = val + '%';
            document.getElementById('val-'+id).textContent = val;
        };
        setBar('rep', '张学良.声望', 50); setBar('rom', '情场.风流值', 20);
        setBar('mil', '奉系势力.军事实力', 50); setBar('fin', '奉系势力.财政储备', 50);
        setBar('pop', '奉系势力.民心向背', 50); setBar('ten', '奉系势力.与日本关系紧张度', 50);

        document.getElementById('v-evt').textContent = v('历史布局.当前进行的事件', '空载');
        document.getElementById('v-str').textContent = v('历史布局.当前战略重心', '空载');

        // 雷达角色映射
        const chars = v('当前在场角色', {});
        const rb = document.getElementById('radar-list');
        if (Object.keys(chars).length === 0) {
            rb.innerHTML = '<div style="text-align:center; color:#8b80b5; padding:10px;">[ 雷达范围内无生命体特征 ]</div>';
        } else {
            let html = '';
            for (const [name, c] of Object.entries(chars)) {
                let icon = c.性别 === '女' ? '<i class="fas fa-venus" style="color:var(--rgb-pink)"></i>' : '<i class="fas fa-mars" style="color:var(--rgb-cyan)"></i>';
                let cloth = '';
                if (c.性别 === '女' && c.各部位衣着) {
                    for(const [pt, text] of Object.entries(c.各部位衣着)) {
                        cloth += `<span class="bio-tag">${pt}:${text}</span>`;
                    }
                }
                html += `
                <div class="bio-card">
                    <div class="bio-head">
                        <div class="bio-name">${name} ${icon}</div>
                        <div style="font-family:monospace; color:var(--rgb-cyan);">好感:${c.好感度}%</div>
                    </div>
                    <div class="bio-thought">『 ${c.当前内心想法 || '精神屏障无法穿透'} 』</div>
                    ${cloth ? `<div style="margin-top:5px;">${cloth}</div>` : ''}
                </div>`;
            }
            rb.innerHTML = html;
        }

        // 情报流终端
        const intel = v('情报网', {});
        const trm = document.getElementById('intel-terminal');
        let thtml = '';
        for (const [src, arr] of Object.entries(intel)) {
            if (Array.isArray(arr)) {
                arr.forEach(msg => {
                    thtml += `<div class="term-line"><span class="term-src">[${src}]</span> ${msg}</div>`;
                });
            }
        }
        trm.innerHTML = thtml || '> 网络深潜无响应数据...';
        trm.scrollTop = trm.scrollHeight;
    }

    // 延迟加载确保数据绑定
    setTimeout(render, 300);
})();
</script>
