            document.getElementById('bar-'+id).style.width = val + '%';
            document.getElementById('val-'+id).textContent = val;
        };
        upBar('rep', '张学良.声望', 50); upBar('rom', '情场.风流值', 20);
        upBar('mil', '奉系势力.军事实力', 50); upBar('fin', '奉系势力.财政储备', 50);
        upBar('pop', '奉系势力.民心向背', 50); upBar('ten', '奉系势力.与日本关系紧张度', 50);

        document.getElementById('v-evt').textContent = v('历史布局.当前进行的事件', '筹算中');
