(function() {
    const hasAll = typeof getAllVariables === 'function';
    const hasLo = typeof _ !== 'undefined' && typeof _.get === 'function';
    const hasTr = typeof triggerSlash === 'function';

    // 交互桥接：坚守护住四大技能名称
    window.execCmd = function(type) {
        if (!hasTr) { alert("指令通讯异常，STscript 接口未挂载。"); return; }
        let input="", cmd="";
        switch(type) {
            case '听令': input = prompt("【听令】意志支配。\n目标及命令 (例: 曹锟 跪下)："); if(input) cmd = `/send 听令 ${input} | /trigger`; break;
            case '观看': input = prompt("【观看】全知视界。\n输入坐标或人名："); if(input) cmd = `/send 观看 ${input} | /trigger`; break;
            case '绿令': input = prompt("【绿令】深层解析。\n输入要扫描的女性姓名："); if(input) cmd = `/send 绿令 ${input} | /trigger`; break;
            case '达令': input = prompt("【达令】空间跃迁。\n目标与目的地 (例: 自己 奉天茶楼)："); if(input) cmd = `/send 达令 ${input} | /trigger`; break;
        }
        if(cmd) triggerSlash(cmd);
    };

    function renderUI() {
        if (!hasAll || !hasLo) return;
        const vars = getAllVariables() || {};
        const v = (p, d) => _.get(vars, 'stat_data.' + p, d);

        // Header & Spatio-Temporal
        document.getElementById('ui-date').textContent = v('当前日期', '1915-01-01');
        document.getElementById('ui-time').textContent = v('当前时间', '00:00');
        document.getElementById('ui-loc').textContent = v('当前位置', 'LOCATION LOST');

        // Focus & Strategy
        document.getElementById('ui-evt').textContent = v('历史布局.当前进行的事件', 'Data Null');
        document.getElementById('ui-str').textContent = v('历史布局.当前战略重心', 'Data Null');

        // Tech Bars Set
        const setBar = (id, path, def) => {
            let val = v(path, def);
            const fill = document.getElementById('up-'+id);
            const txt = document.getElementById('tv-'+id);
            if(fill) fill.style.width = val + '%';
            if(txt) txt.textContent = val;
        };
        setBar('rep', '张学良.声望', 50); setBar('rom', '情场.风流值', 20);
        setBar('mil', '奉系势力.军事实力', 50); setBar('fin', '奉系势力.财政储备', 50);
        setBar('pop', '奉系势力.民心向背', 50); setBar('ten', '奉系势力.与日本关系紧张度', 50);

        // Radar: Target Detection
        const chars = v('当前在场角色', {});
        const rp = document.getElementById('radar-pane');
        if (Object.keys(chars).length === 0) {
            rp.innerHTML = '<div style="text-align: center; color: var(--so-text-sub); padding: 10px; font-size: 12px; opacity: 0.7;">[ NO TARGET DETECTED ]</div>';
        } else {
            let html = '';
            for (const [name, c] of Object.entries(chars)) {
                let isF = c.性别 === '女';
                let icon = isF ? '<i class="fas fa-venus" style="color:var(--so-green)"></i>' : '<i class="fas fa-mars" style="color:var(--so-gold)"></i>';
                let cloth = '';
                if (isF && c.各部位衣着) {
                    for(const [pt, text] of Object.entries(c.各部位衣着)) {
                        cloth += `<div class="pill">${pt}: ${text}</div>`;
                    }
                }
                html += `
                <div class="target-box">
                    <div class="target-hdr">
                        <div class="target-name">${name} ${icon}</div>
                        <div style="font-size:11px; font-family:monospace; color:var(--so-text-sub);">FAVOR: <span style="color:var(--so-text-main)">${c.好感度}%</span></div>
                    </div>
                    <div class="target-mind">${c.当前内心想法 || 'ENCRYPTED...'}</div>
                    ${cloth ? `<div class="cloth-pills">${cloth}</div>` : ''}
                </div>`;
            }
            rp.innerHTML = html;
        }

        // Intel Network Scroll
        const intel = v('情报网', {});
        const ip = document.getElementById('intel-pane');
        let iHtml = '';
        for (const [src, arr] of Object.entries(intel)) {
            if (Array.isArray(arr) && arr.length > 0) {
                arr.forEach(msg => {
                    iHtml += `<div class="intel-line"><span class="intel-src">[${src}]</span> ${msg}</div>`;
                });
            }
        }
        ip.innerHTML = iHtml || '<div style="opacity:0.5;">No incoming intel signals.</div>';
        ip.scrollTop = ip.scrollHeight;
    }

    setTimeout(renderUI, 300);
})();
</script>
